import {
  createContext,
  useContext,
  useSyncExternalStore,
  type PropsWithChildren,
} from 'react';
import {
  createDefaultKangurProgressState,
  type KangurProgressState,
} from '@kangur/contracts/kangur';

import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';

type KangurMobileHomeProgressSnapshotContextValue = {
  progress: KangurProgressState;
  subscribeToProgressStore: boolean;
};

const KangurMobileHomeProgressSnapshotContext =
  createContext<KangurMobileHomeProgressSnapshotContextValue | null>(null);

const subscribeToProvidedHomeProgressSnapshot = (): (() => void) => () => {};

export const KangurMobileHomeProgressSnapshotProvider = ({
  children,
  progress,
  subscribeToProgressStore = false,
}: PropsWithChildren<{
  progress: KangurProgressState;
  subscribeToProgressStore?: boolean;
}>): React.JSX.Element => (
  <KangurMobileHomeProgressSnapshotContext.Provider
    value={{
      progress,
      subscribeToProgressStore,
    }}
  >
    {children}
  </KangurMobileHomeProgressSnapshotContext.Provider>
);

export const useKangurMobileHomeProgressSnapshot = (): KangurProgressState => {
  const providedProgressSnapshot = useContext(KangurMobileHomeProgressSnapshotContext);
  const { progressStore } = useKangurMobileRuntime();
  const shouldSubscribeToProgressStore =
    providedProgressSnapshot?.subscribeToProgressStore ?? true;
  const providedProgress = providedProgressSnapshot?.progress ?? null;

  return useSyncExternalStore(
    shouldSubscribeToProgressStore
      ? progressStore.subscribeToProgress
      : subscribeToProvidedHomeProgressSnapshot,
    shouldSubscribeToProgressStore
      ? progressStore.loadProgress
      : () => providedProgress ?? createDefaultKangurProgressState(),
    shouldSubscribeToProgressStore
      ? providedProgress
        ? () => providedProgress
        : createDefaultKangurProgressState
      : () => providedProgress ?? createDefaultKangurProgressState(),
  );
};

import { Text, View } from 'react-native';
import { useKangurMobileI18n } from '../../i18n/kangurMobileI18n';
import { translateKangurMobileActionLabel } from '../../shared/translateKangurMobileActionLabel';
import type { KangurMobileHomeAssignmentItem } from '../useKangurMobileHomeAssignments';
import { OutlineLink, SummaryChip } from '../homeScreenPrimitives';

function getPriorityConfig(priority: string, copy: (args: Record<string, string>) => string) {
  if (priority === 'high') {
    return { accent: 'rose' as const, label: copy({ de: 'Hohe Priorität', en: 'High priority', pl: 'Priorytet wysoki' }) };
  }
  if (priority === 'medium') {
    return { accent: 'amber' as const, label: copy({ de: 'Mittlere Priorität', en: 'Medium priority', pl: 'Priorytet średni' }) };
  }
  return { accent: 'blue' as const, label: copy({ de: 'Niedrige Priorität', en: 'Low priority', pl: 'Priorytet niski' }) };
}

export function AssignmentCard({
  item,
}: {
  item: KangurMobileHomeAssignmentItem;
}): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  const actionLabel = translateKangurMobileActionLabel(item.assignment.action.label, locale);
  const { accent, label } = getPriorityConfig(item.assignment.priority, copy);

  const assignmentAction = item.href ? (
    <OutlineLink href={item.href} hint={item.assignment.description} label={actionLabel} />
  ) : (
    <View
      style={{
        alignSelf: 'flex-start',
        borderRadius: 999,
        backgroundColor: '#e2e8f0',
        paddingHorizontal: 14,
        paddingVertical: 10,
      }}
    >
      <Text style={{ color: '#475569', fontWeight: '700' }}>
        {actionLabel} · {copy({ de: 'bald', en: 'soon', pl: 'wkrotce' })}
      </Text>
    </View>
  );

  return (
    <View
      style={{
        backgroundColor: '#f8fafc',
        borderColor: '#e2e8f0',
        borderRadius: 20,
        borderWidth: 1,
        gap: 10,
        padding: 14,
      }}
    >
      <SummaryChip accent={accent} label={label} />
      <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '800' }}>
        {item.assignment.title}
      </Text>
      <Text style={{ color: '#475569', lineHeight: 20 }}>
        {item.assignment.description}
      </Text>
      <Text style={{ color: '#64748b', lineHeight: 20 }}>
        {copy({ de: `Ziel: ${item.assignment.target}`, en: `Goal: ${item.assignment.target}`, pl: `Cel: ${item.assignment.target}` })}
      </Text>
      {assignmentAction}
    </View>
  );
}

import { Text, View } from 'react-native';
import { useKangurMobileI18n } from '../../i18n/kangurMobileI18n';
import { formatKangurMobileScoreOperation } from '../../scores/mobileScoreSummary';
import { createKangurResultsHref } from '../../scores/resultsHref';
import { OutlineLink } from '../homeScreenPrimitives';
import type { Href } from 'expo-router';

export function FocusCard({
  actionHref,
  actionLabel,
  averageAccuracyPercent,
  lessonHref,
  operation,
  sessions,
  title,
}: {
  actionHref: Href;
  actionLabel: string;
  averageAccuracyPercent: number;
  lessonHref: Href | null;
  operation: string;
  sessions: number;
  title: string;
}): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  const operationLabel = formatKangurMobileScoreOperation(operation, locale);

  const lessonAction = lessonHref !== null ? (
    <OutlineLink
      href={lessonHref}
      hint={copy({
        de: `Öffnet die Lektion für den Modus ${operationLabel}.`,
        en: `Opens the lesson for the ${operationLabel} mode.`,
        pl: `Otwiera lekcję dla trybu ${operationLabel}.`,
      })}
      label={`${copy({
        de: 'Lektion öffnen',
        en: 'Open lesson',
        pl: 'Otwórz lekcję',
      })}: ${operationLabel}`}
    />
  ) : null;

  return (
    <View
      style={{
        backgroundColor: '#f8fafc',
        borderColor: '#e2e8f0',
        borderRadius: 20,
        borderWidth: 1,
        gap: 10,
        padding: 14,
      }}
    >
      <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>
        {title}
      </Text>
      <Text style={{ color: '#0f172a', fontSize: 20, fontWeight: '800' }}>
        {operationLabel}
      </Text>
      <Text style={{ color: '#475569', lineHeight: 20 }}>
        {copy({
          de: `Trefferquote ${averageAccuracyPercent}% in ${sessions} Versuchen.`,
          en: `Accuracy ${averageAccuracyPercent}% across ${sessions} attempts.`,
          pl: `Skuteczność ${averageAccuracyPercent}% w ${sessions} podejściach.`,
        })}
      </Text>
      <View style={{ flexDirection: 'column', gap: 8 }}>
        <OutlineLink
          href={actionHref}
          hint={copy({
            de: `Öffnet das Training für den Modus ${operationLabel}.`,
            en: `Opens practice for the ${operationLabel} mode.`,
            pl: `Otwiera trening dla trybu ${operationLabel}.`,
          })}
          label={`${actionLabel}: ${operationLabel}`}
        />
        {lessonAction}
        <OutlineLink
          href={createKangurResultsHref({ operation })}
          hint={copy({
            de: `Öffnet den Ergebnisverlauf für den Modus ${operationLabel}.`,
            en: `Opens result history for the ${operationLabel} mode.`,
            pl: `Otwiera historię wyników dla trybu ${operationLabel}.`,
          })}
          label={`${copy({
            de: 'Modusverlauf',
            en: 'Mode history',
            pl: 'Historia trybu',
          })}: ${operationLabel}`}
        />
      </View>
    </View>
  );
}

import React from 'react';
import { Text } from 'react-native';
import {
  DeferredHomeAccountDetails,
  DeferredHomeAccountSummary,
  PrimaryButton,
  SectionCard,
} from '../homeScreenPrimitives';
import { HomeLearnerCredentialsSignInSection } from './HomeLearnerCredentialsSignInSection';
import { type getKangurHomeAuthBoundaryViewModel } from '../homeAuthBoundary';
import { type useKangurMobileI18n } from '../../i18n/kangurMobileI18n';

type HomeAccountSectionProps = {
  areDeferredHomeAccountSummaryReady: boolean;
  areDeferredHomeAccountDetailsReady: boolean;
  areDeferredHomeAccountSignInReady: boolean;
  authBoundary: ReturnType<typeof getKangurHomeAuthBoundaryViewModel> | null;
  authMode: string | null;
  authError: string | null;
  apiBaseUrl: string;
  apiBaseUrlSource: string;
  shouldShowLearnerCredentialsForm: boolean;
  sessionStatus: string;
  signIn: () => void;
  signInWithLearnerCredentials: (loginName: string, password: string) => Promise<void>;
  signOut: () => void;
  copy: ReturnType<typeof useKangurMobileI18n>['copy'];
};

export function HomeAccountSection({
  areDeferredHomeAccountSummaryReady,
  areDeferredHomeAccountDetailsReady,
  areDeferredHomeAccountSignInReady,
  authBoundary,
  authMode,
  authError,
  apiBaseUrl,
  apiBaseUrlSource,
  shouldShowLearnerCredentialsForm,
  sessionStatus,
  signIn,
  signInWithLearnerCredentials,
  signOut,
  copy,
}: HomeAccountSectionProps): React.JSX.Element {
  let content: React.JSX.Element;

  if (!areDeferredHomeAccountSummaryReady) {
    content = <DeferredHomeAccountSummary />;
  } else {
    content = (
      <>
        <Text accessibilityLiveRegion='polite' style={{ color: '#0f172a' }}>
          {copy({
            de: 'Status',
            en: 'Status',
            pl: 'Status',
          })}
          : {authBoundary?.statusLabel}
        </Text>
        <Text style={{ color: '#475569' }}>
          {copy({
            de: 'Nutzer',
            en: 'User',
            pl: 'Użytkownik',
          })}
          : {authBoundary?.userLabel}
        </Text>
        {!areDeferredHomeAccountDetailsReady ? (
          <DeferredHomeAccountDetails />
        ) : (
          <>
            <Text style={{ color: '#475569' }}>
              {copy({
                de: 'Anmeldemodus',
                en: 'Sign-in mode',
                pl: 'Tryb logowania',
              })}
              : {authMode}
            </Text>
            <Text style={{ color: '#475569' }}>
              API: {apiBaseUrl} ({apiBaseUrlSource})
            </Text>
          </>
        )}
      </>
    );
  }

  let action: React.JSX.Element;
  if (shouldShowLearnerCredentialsForm) {
    action = (
      <HomeLearnerCredentialsSignInSection
        isDeferredReady={areDeferredHomeAccountSignInReady}
        onSignIn={signInWithLearnerCredentials}
      />
    );
  } else if (sessionStatus === 'authenticated') {
    action = (
      <PrimaryButton
        hint={copy({
          de: 'Meldet das aktuelle Konto ab.',
          en: 'Signs out the current account.',
          pl: 'Wylogowuje bieżące konto.',
        })}
        label={copy({
          de: 'Abmelden',
          en: 'Sign out',
          pl: 'Wyloguj',
        })}
        onPress={() => {
          signOut();
        }}
      />
    );
  } else {
    action = (
      <PrimaryButton
        hint={copy({
          de: 'Startet die Demo.',
          en: 'Starts the demo.',
          pl: 'Uruchamia demo.',
        })}
        label={copy({
          de: 'Demo starten',
          en: 'Start demo',
          pl: 'Uruchom demo',
        })}
        onPress={() => {
          signIn();
        }}
      />
    );
  }

  return (
    <SectionCard
      title={copy({
        de: 'Konto und Verbindung',
        en: 'Account and connection',
        pl: 'Konto i połączenie',
      })}
    >
      {content}
      {authError !== null && authError !== '' ? (
        <Text style={{ color: '#b91c1c', lineHeight: 20 }}>{authError}</Text>
      ) : null}
      {action}
    </SectionCard>
  );
}

import React from 'react';
import { Text, View } from 'react-native';
import { useKangurMobileI18n } from '../../i18n/kangurMobileI18n';
import { SectionCard, PrimaryButton, OutlineLink } from '../homeScreenPrimitives';
import { useKangurMobileHomeDuelsLeaderboard } from '../useKangurMobileHomeDuelsLeaderboard';
import { DUELS_ROUTE } from '../home-screen-constants';

interface HomeDuelLeaderboardSectionProps {
  activeDuelLearnerId: string | null;
  isAuthenticated: boolean;
}

export function HomeDuelLeaderboardSection({
  activeDuelLearnerId,
  isAuthenticated,
}: HomeDuelLeaderboardSectionProps): React.JSX.Element {
  const { copy } = useKangurMobileI18n();
  const duelLeaderboard = useKangurMobileHomeDuelsLeaderboard({
    enabled: true,
  });

  return (
    <SectionCard
      title={copy({
        de: 'Duell-Rangliste',
        en: 'Duel leaderboard',
        pl: 'Ranking pojedynków',
      })}
    >
      {duelLeaderboard.isLoading ? (
        <Text style={{ color: '#475569', lineHeight: 20 }}>
          {copy({
            de: 'Die Duell-Rangliste wird geladen.',
            en: 'Loading the duel leaderboard.',
            pl: 'Pobieramy ranking pojedynków.',
          })}
        </Text>
      ) : duelLeaderboard.error ? (
        <View style={{ gap: 10 }}>
          <Text style={{ color: '#b91c1c', lineHeight: 20 }}>
            {duelLeaderboard.error}
          </Text>
          <PrimaryButton
            hint={copy({
              de: 'Aktualisiert die Duell-Rangliste.',
              en: 'Refreshes the duel leaderboard.',
              pl: 'Odświeża ranking pojedynków.',
            })}
            label={copy({
              de: 'Ranking aktualisieren',
              en: 'Refresh leaderboard',
              pl: 'Odśwież ranking',
            })}
            onPress={duelLeaderboard.refresh}
          />
        </View>
      ) : duelLeaderboard.entries.length === 0 ? (
        <View style={{ gap: 10 }}>
          <Text style={{ color: '#475569', lineHeight: 20 }}>
            {copy({
              de: 'Noch keine abgeschlossenen Duelle in diesem Fenster. Die ersten beendeten Serien füllen hier sofort diesen Duellstand.',
              en: 'There are no completed duels in this window yet. The first finished series will fill this duel standing right away.',
              pl: 'W tym oknie nie ma jeszcze zakończonych pojedynków. Pierwsze skończone serie od razu wypełnią tutaj ten stan pojedynków.',
            })}
          </Text>
          <OutlineLink
            href={DUELS_ROUTE}
            hint={copy({
              de: 'Öffnet die Duell-Lobby.',
              en: 'Opens the duels lobby.',
              pl: 'Otwiera lobby pojedynków.',
            })}
            label={copy({
              de: 'Duell-Lobby öffnen',
              en: 'Open duels lobby',
              pl: 'Otwórz lobby pojedynków',
            })}
          />
        </View>
      ) : (
        <Text>{copy({ de: 'Rangliste verfügbar', en: 'Leaderboard available', pl: 'Ranking dostępny' })}</Text>
      )}
    </SectionCard>
  );
}

import React from 'react';
import {
  AuthenticatedHomePrivateDuelSectionGroup,
  AuthenticatedHomeRematchesSection,
  AnonymousHomePrivateDuelSectionGroup,
  AnonymousHomeRematchesSection,
  DeferredDuelAdvancedSectionPlaceholder,
  HomeDuelLeaderboardSection,
  HomeLiveDuelsSection,
} from '../HomeDuelSections';
import { SectionCard } from '../homeScreenPrimitives';
import { DeferredHomeActivitySectionsCard } from '../home-screen-deferred';
import { type useKangurMobileI18n } from '../../i18n/kangurMobileI18n';

type HomeDuelSectionsGroupProps = {
  areDeferredHomePanelsReady: boolean;
  areDeferredHomeDuelAdvancedReady: boolean;
  areDeferredHomeDuelInvitesReady: boolean;
  areDeferredHomeDuelSecondaryReady: boolean;
  isAuthenticated: boolean;
  activeDuelLearnerId: string | null;
  shouldRenderCombinedHomeStartupPlaceholder: boolean;
  copy: ReturnType<typeof useKangurMobileI18n>['copy'];
};

export function HomeDuelSectionsGroup({
  areDeferredHomePanelsReady,
  areDeferredHomeDuelAdvancedReady,
  areDeferredHomeDuelInvitesReady,
  areDeferredHomeDuelSecondaryReady,
  isAuthenticated,
  activeDuelLearnerId,
  shouldRenderCombinedHomeStartupPlaceholder,
  copy,
}: HomeDuelSectionsGroupProps): React.JSX.Element | null {
  if (!areDeferredHomePanelsReady) {
    if (shouldRenderCombinedHomeStartupPlaceholder) {
      return null;
    }
    return <DeferredHomeActivitySectionsCard />;
  }

  const PrivateDuelSectionGroup = isAuthenticated
    ? AuthenticatedHomePrivateDuelSectionGroup
    : AnonymousHomePrivateDuelSectionGroup;

  const RematchesSection = isAuthenticated
    ? AuthenticatedHomeRematchesSection
    : AnonymousHomeRematchesSection;

  return (
    <>
      <PrivateDuelSectionGroup
        areDeferredHomeDuelAdvancedReady={areDeferredHomeDuelAdvancedReady}
        areDeferredHomeDuelInvitesReady={areDeferredHomeDuelInvitesReady}
        areDeferredHomeDuelSecondaryReady={areDeferredHomeDuelSecondaryReady}
        areDeferredHomePanelsReady={areDeferredHomePanelsReady}
      />

      {!areDeferredHomeDuelAdvancedReady ? (
        <SectionCard
          title={copy({
            de: 'Live-Duelle',
            en: 'Live duels',
            pl: 'Na żywo w pojedynkach',
          })}
        >
          <DeferredDuelAdvancedSectionPlaceholder />
        </SectionCard>
      ) : (
        <HomeLiveDuelsSection isAuthenticated={isAuthenticated} />
      )}

      <RematchesSection
        areDeferredHomeDuelAdvancedReady={areDeferredHomeDuelAdvancedReady}
        areDeferredHomeDuelInvitesReady={areDeferredHomeDuelInvitesReady}
        areDeferredHomeDuelSecondaryReady={areDeferredHomeDuelSecondaryReady}
        areDeferredHomePanelsReady={areDeferredHomePanelsReady}
      />

      {!areDeferredHomeDuelAdvancedReady ? (
        <SectionCard
          title={copy({
            de: 'Duell-Rangliste',
            en: 'Duel leaderboard',
            pl: 'Ranking pojedynków',
          })}
        >
          <DeferredDuelAdvancedSectionPlaceholder />
        </SectionCard>
      ) : (
        <HomeDuelLeaderboardSection
          activeDuelLearnerId={activeDuelLearnerId}
          isAuthenticated={isAuthenticated}
        />
      )}
    </>
  );
}

